<template>
    <div class="head">
        <label class="title">{{ t('pages.favorite.title') }}</label>    
        <IconButton icon="settings" class="tertiary size-l" @click="nav.open('settings')" />
    </div>

    <Tracks v-if="data.ready"
        type="row"
        :take="12"
        :source="{
            store: 'favorite',
            fnName: 'getTracks'
        }"
        handler="track"
        :loadMore="false"
        :buttons="[{
            name: 'blocks.tracks.all',
            page: 'favorite-tracks',
            hideIfEmpty: true
        }]"
        :empty="{
            icon: 'favorite',
            title: t('pages.favorite.tracks.empty.title'),
            description: t('pages.favorite.tracks.empty.description')
        }"
        :showKebab="true"
        :sort="{
            code: 'releaseDate',
            direction: 'desc'
        }"
        title="pages.favorite.tracks.title"
    />

    <div class="more">
        <label class="title">{{ t('pages.favorite.more.title') }}</label>

        <div>
            <!-- Playlists -->
            <Button icon="playlist"
                :name="t('pages.favorite.playlists.title')"
                class="tap"
                @click="data.playlistsPreview?.length === 1 ? nav.open('playlist', { id: data.playlistsPreview[0].id }) : nav.open('favorite-playlists')">
                <template v-slot:collage v-if="data.playlistsPreview.length">
                    <Collage :items="data.playlistsPreview.map(item => item.cover)"
                        :default="defaultPlaylistCover"
                        borderRadius="12px"
                    />
                </template>
            </Button>

            <!-- Artists -->
            <Button icon="artists"
                :name="t('pages.favorite.artists.title')"
                class="tap"
                @click="data.artistsPreview?.length === 1 ? nav.open('artist', { code: data.artistsPreview[0].code }) : nav.open('favorite-artists')">
                <template v-slot:collage v-if="data.artistsPreview.length">
                    <Collage :items="data.artistsPreview.map(item => item.profileImage)"
                        :default="defaultProfileImage"
                        borderRadius="12px"
                    />
                </template>
            </Button>

            <!-- Releases -->
            <Button icon="release"
                :name="t('pages.favorite.releases.title')"
                class="tap"
                @click="data.releasesPreview?.length === 1 ? nav.open('release', { id: data.releasesPreview[0].id }) : nav.open('favorite-releases')">
                <template v-slot:collage v-if="data.releasesPreview.length">
                    <Collage :items="data.releasesPreview.map(item => item.cover)"
                        :default="defaultReleaseCover"
                        borderRadius="12px"
                    />
                </template>
            </Button>

            <!-- My Artists -->
            <Button v-if="data.myArtistsPreview?.length"
                :name="t('pages.favorite.my-artists.title')"
                class="tap"
                @click="data.myArtistsPreview?.length === 1 ? nav.open('artist', { code: data.myArtistsPreview[0].code }) : nav.open('favorite-my-artists')">
                <template v-slot:collage v-if="data.myArtistsPreview.length">
                    <Collage :items="data.myArtistsPreview.map(item => item.profileImage)"
                        :default="defaultProfileImage"
                        borderRadius="12px"
                    />
                </template>
            </Button>
        </div>
    </div>

    <Ready page="favorite" :init="init" />


<!--     <TgsViewer url="/tgs/stick-1.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-2.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-1.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-1.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-1.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-1.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-1.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-3.tgs" :size="80" />
    <TgsViewer url="/tgs/stick-4.tgs" :size="80" /> -->


</template>

<script setup>
    import { computed, onMounted, onBeforeUnmount, reactive, ref } from 'vue';
    import { useI18n } from 'vue-i18n';
    import IconButton from '🔗/components/ui/IconButton.vue';
    import Tracks from '🔗/components/blocks/Tracks.vue';
    import Button from '🔗/components/ui/Button.vue';
    import EmptyLabel from '🔗/components/ui/EmptyLabel.vue';
    import Collage from '🔗/components/ui/Collage.vue';
    import Ready from '🔗/components/ui/Ready.vue';
    import api from '🔗/api';

    // import TgsViewer from '🔗/components/ui/TgsViewer.vue';


    const { t } = useI18n();



    import stores from '@/stores';

    const user = stores.user();
    const nav = stores.nav();
    const messengers = stores.messengers();

    const others = stores.others();


    const data = reactive({
        ready: false,
        myArtistsPreview: [],
        artistsPreview: [],
        releasesPreview: [],
        playlistsPreview: []
    });

    const defaultProfileImage = computed(() => {
        return api.artists().defaultProfileImage;
    });

    const defaultReleaseCover = computed(() => {
        return api.artists().defaultCover;
    });

    const defaultPlaylistCover = computed(() => {
        return api.playlists().defaultCover;
    });
    

    // Preview
        const getMyArtistsPreview = async () => {
            const payload = await api.user().getMyArtistsPreview();

            data.myArtistsPreview = payload?.items || [];
        }

        const getArtistsPreview = async () => {
            const payload = await api.favorite().artists.preview();
            data.artistsPreview = payload?.items || [];
        }

        const getReleasesPreview = async () => {
            const payload = await api.favorite().releases.preview();
            data.releasesPreview = payload?.items || [];
        }

        const getPlaylistsPreview = async () => {
            const payload = await api.favorite().playlists.preview();
            data.playlistsPreview = payload?.items || [];
        }

    const init = async () => {
        getMyArtistsPreview();
        getArtistsPreview();
        getReleasesPreview();
        getPlaylistsPreview();

        data.ready = true;
    }

    const openSettings = () => {
        stores.nav().open('settings');
    }

    onMounted(() => {
        messengers.showSettingsButton(openSettings);
    });

    onBeforeUnmount(() => {
        messengers.hideSettingsButton(openSettings);
    });
</script>

<style lang="scss" scoped>
    .head {
        @include page-title;
    }

    .more {
        padding: 0 16px var(--block-gap);
        display: flex;
        flex-direction: column;
        gap: 32px;
        width: 100%;
        justify-content: start;
        .title {
            font: var(--font-h6);
            font-weight: bold;
            color: var(--dark-500);
        }

        & > div {
            display: flex;
            flex-direction: row;
            gap: 8px;
            flex-wrap: wrap;

            button {
                flex: 1 1 50%;
                max-width: calc(50% - 4px);
            }
        }
    }
</style>
